/// <summary>
/// This is an UIBuilder class for report CylinderTrackingInputReport
/// </summary>
internal final class ETGCylinderTrackingInputReportUIBuilder extends SrsReportDataContractUIBuilder
{
    ETGCylinderTrackingInputReportContract contract;
    DialogField dialogFromDate;
    DialogField dialogToDate;
    DialogField custAccount;
    DialogField etgBussinessSegment;
    DialogField etgFilledOrEmpty;
    DialogField deposit;
    DialogField etgConnectionType;
    DialogField productNum;


}

Method.Source:
public void build()
{
    contract            = this.dataContractObject() as ETGCylinderTrackingInputReportContract;
    dialogFromDate      = this.addDialogField(methodStr(ETGCylinderTrackingInputReportContract, parmFromDate), contract);
    dialogToDate        = this.addDialogField(methodStr(ETGCylinderTrackingInputReportContract, parmToDate), contract);
    custAccount         = this.addDialogField(methodStr(ETGCylinderTrackingInputReportContract, parmCustAccount), contract);
    etgBussinessSegment = this.addDialogField(methodStr(ETGCylinderTrackingInputReportContract, parmBusinessSegment), contract);
    etgFilledOrEmpty    = this.addDialogField(methodStr(ETGCylinderTrackingInputReportContract, parmFilledOrEmpty), contract);
    deposit             = this.addDialogField(methodStr(ETGCylinderTrackingInputReportContract, parmDeposit), contract);
    etgConnectionType   = this.addDialogField(methodStr(ETGCylinderTrackingInputReportContract, parmConnectionType), contract);
    productNum          = this.addDialogField(methodStr(ETGCylinderTrackingInputReportContract, parmProductNum), contract);
}

public void postBuild()
{
    Dialog dialogobj = this.dialog();
    super();
    dialogFromDate      = this.bindInfo().getDialogField(contract, methodStr(ETGCylinderTrackingInputReportContract, parmFromDate));
    dialogToDate        = this.bindInfo().getDialogField(contract, methodStr(ETGCylinderTrackingInputReportContract, parmToDate));
    custAccount         = this.bindInfo().getDialogField(contract, methodStr(ETGCylinderTrackingInputReportContract, parmCustAccount));
    custAccount.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGCylinderTrackingInputReportUIBuilder, custAccountMultiSelectLookup), this);
    etgBussinessSegment = this.bindInfo().getDialogField(contract, methodStr(ETGCylinderTrackingInputReportContract, parmBusinessSegment));
    etgFilledOrEmpty    = this.bindInfo().getDialogField(contract, methodStr(ETGCylinderTrackingInputReportContract, parmFilledOrEmpty));
    deposit             = this.bindInfo().getDialogField(contract, methodStr(ETGCylinderTrackingInputReportContract, parmDeposit));
    etgConnectionType   = this.bindInfo().getDialogField(contract, methodStr(ETGCylinderTrackingInputReportContract, parmConnectionType));
    productNum          = this.bindInfo().getDialogField(contract, methodStr(ETGCylinderTrackingInputReportContract, parmProductNum));
    productNum.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETGCylinderTrackingInputReportUIBuilder, productMultiSelectLookup), this);
    productNum.fieldControl().mandatory(true);

}

public void postRun()
{
    ETGCylinderTrackingInputReportContract etgCylinderTrackingInputReportContract = this.dataContractObject();
}

/// <summary>
/// Multiselect lookup for cust account parameter
/// </summary>
/// <param name = "_control">FormStringControl</param>
public void custAccountMultiSelectLookup(FormStringControl _control)
{
    Query                 query = new Query();
    QueryBuildDataSource  qbds;
    container             conCustTable;

    qbds = query.addDataSource(tableNum(CustTable));

    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(CustTable,AccountNum));

    qbds = qbds.addDataSource(tableNum(DirPartyTable));
    qbds.fields().dynamic(NoYes::Yes);
    qbds.fields().addField(fieldNum(DirPartyTable,Name));
    qbds.relations(true);
    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conCustTable);
}

/// <summary>
/// Multiselect lookup for Product number parameter
/// </summary>
/// <param name = "_control">FormStringControl</param>
public void productMultiSelectLookup(FormStringControl _control)
{
    Query                 query = new Query();
    QueryBuildDataSource  qbds;
    container             conProduct;

    qbds = query.addDataSource(tableNum(InventTable));

    qbds.addSelectionField(fieldNum(InventTable, ItemId));
    qbds.addSelectionField(fieldNum(InventTable, NameAlias));
    qbds.addSelectionField(fieldNum(InventTable, ItemType));
    qbds.addSelectionField(fieldNum(InventTable, Product));

    SysLookUpMultiSelectGrid::lookup(query, _control, _control, _control,conProduct);
}
